const body = $input.first().json.body ?? $input.first().json;
const company = body.company || '';
if (!company) throw new Error('No company name provided');
return [
  { json: { company, query: company + ' telecom digital transformation AI autonomous networks 2024 2025' } },
  { json: { company, query: company + ' CTO CIO technology leadership team digital' } },
  { json: { company, query: company + ' 5G BSS OSS network modernization cloud transformation' } }
];

const allItems = $input.all();
const company = allItems[0].json.company || 'Unknown';

// Combine search results from all 3 searches
const allResults = allItems.flatMap(item => {
  const data = item.json.data || [];
  return data.slice(0, 4).map(r => ({
    title: r.title || '',
    url: r.url || '',
    description: r.description || '',
    content: (r.markdown || r.content || '').slice(0, 400)
  }));
});

const searchContext = allResults.map((r, i) =>
  `[${i+1}] ${r.title}
${r.url}
${r.description}
${r.content}`
).join('

---

');

const systemPrompt = `You are a TM Forum ODA membership prospecting researcher for Claire Watson's team.

Analyse web search results about a telecoms or satellite operator. Return ONLY valid JSON with no markdown wrapper, matching this exact schema:
{
  "company": "full company name",
  "slug": "kebab-case-slug",
  "overview": {
    "hq": "City, Country",
    "size": "subscriber count or revenue if found",
    "ownership": "listed / state-owned / private / group subsidiary",
    "services": "mobile, fixed, broadband, satellite, fintech etc"
  },
  "score": 0,
  "maxScore": 30,
  "verdict": "Strong",
  "topSignals": ["signal 1", "signal 2", "signal 3"],
  "primaryMission": "Autonomous Networks",
  "secondaryMission": null,
  "keyContacts": [{"name": "Name", "title": "Title"}],
  "timingHook": "specific reason to reach out now, or null",
  "summary": "3-4 sentence narrative on why this operator is a strong TM Forum ODA prospect",
  "researchNotes": "any data gaps or caveats"
}

Primary mission options: Autonomous Networks | AI & Data | Composable IT & Ecosystems | Business Assurance | Business Process/eTOM

Scoring (max 30 pts):
3 pts each: active AI/automation programme, cloud-native BSS/OSS transformation, multi-OPCO group, 5G rollout in progress, public digital transformation strategy, TM Forum event attendance, ODA-aligned vendors (Ericsson/Nokia/Huawei/Amdocs/Netcracker)
2 pts each: revenue growth or market expansion, ESG commitments, B2B or API marketplace ambitions, recent MéA or ownership change, regulatory compliance pressure
1 pt each: generic digital language, event attendance as delegate, non-ODA vendor relationships

Verdict: 15+ = Strong, 8-14 = Moderate, <8 = Weak`;

const claudeBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 2000,
  system: systemPrompt,
  messages: [{
    role: 'user',
    content: `Research ${company} based on these web search results:

${searchContext}

Return the JSON research brief for ${company}.`
  }]
};

return [{ json: { company, claudeBody } }];

const item = $input.first().json;
const raw = item.content?.[0]?.text || item.choices?.[0]?.message?.content || '';

let research;
try {
  // Strip any markdown code fences if present
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/\s*```$/,'').trim();
  research = JSON.parse(cleaned);
} catch(e) {
  return [{ json: { success: false, error: 'Failed to parse research: ' + e.message, raw } }];
}

return [{ json: { success: true, research } }];
